// C3: Physical sensing components
instance MotorEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor position encoder on the permanent‑magnet synchronous motor of the first axis"
    DTDFVocab:producedData MotorEncoderDataTransmitted
]

instance GearboxEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary position encoder located behind the gearwheel/gearbox of the first axis"
    DTDFVocab:producedData GearboxEncoderDataTransmitted
]

instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Sensor measuring motor input current I_M of the first axis"
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

// C4: Physical-to-virtual interaction (DataTransmitted)
instance MotorEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoder
]

instance GearboxEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoder
]

instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

// C10: Data
instance MotorAngularPositionData : DTDFVocab:Data [
    base:desc "Angular position of the motor shaft derived from MotorEncoder"
    DTDFVocab:fromData MotorEncoderDataTransmitted
    DTDFVocab:inputTo SimulinkTool
]

instance GearboxAngularPositionData : DTDFVocab:Data [
    base:desc "Angular position after gearbox derived from GearboxEncoder"
    DTDFVocab:fromData GearboxEncoderDataTransmitted
    DTDFVocab:inputTo SimulinkTool
]

instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Measured motor input current I_M"
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo SimulinkTool
]

instance DerivedTorqueData : DTDFVocab:Data [
    base:desc "Derived torque computed from motor current I_M and motor model"
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo SimulinkTool
]

instance DerivedAngularVelocityData : DTDFVocab:Data [
    base:desc "Angular velocity derived from motor position data"
    DTDFVocab:fromData MotorEncoderDataTransmitted
    DTDFVocab:inputTo SimulinkTool
]

instance DerivedAngularAccelerationData : DTDFVocab:Data [
    base:desc "Angular acceleration derived from motor position data"
    DTDFVocab:fromData MotorEncoderDataTransmitted
    DTDFVocab:inputTo SimulinkTool
]

// C10: Models
instance SysMLAxisModel : DTDFVocab:Model [
    base:desc "SysML block definition and internal block diagram of the first axis"
