]

instance SimulinkMotorModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink model of the permanent‑magnet synchronous motor"
    DTDFVocab:inputTo SimulinkTool
]

instance SimulinkGearwheelModel : DTDFVocab:Model [
    base:desc "Simulink model of the gearwheel gearbox"
    DTDFVocab:inputTo SimulinkTool
]

instance SimulinkGearboxModel : DTDFVocab:Model [
    base:desc "Simulink model of the cycloidal gearbox"
    DTDFVocab:inputTo SimulinkTool
]

instance SimulinkFrictionFreeModel : DTDFVocab:Model [
    base:desc "Friction‑free simulation model for baseline behavior"
    DTDFVocab:inputTo SimulinkTool
]

instance SimulinkFrictionModel : DTDFVocab:Model [
    base:desc "Friction model (static, kinetic, viscous) for the axis"
    DTDFVocab:inputTo SimulinkTool
]

instance TorqueCalculationModel : DTDFVocab:Model [
    base:desc "Data calculation model generating torque from current and motor parameters"
    DTDFVocab:inputTo SimulinkTool
]

instance VelocityCalculationModel : DTDFVocab:Model [
    base:desc "Data calculation model generating angular velocity from position data"
    DTDFVocab:inputTo SimulinkTool
]

instance AccelerationCalculationModel : DTDFVocab:Model [
    base:desc "Data calculation model generating angular acceleration from position data"
    DTDFVocab:inputTo SimulinkTool
]

// C11: Enablers
instance SysMLTool : DTDFVocab:Enabler [
    base:desc "SysML modeling environment for creating the engineering model of the robot axis"
    DTDFVocab:enables FrictionParameterUpdateService
]

instance SimulinkTool : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink environment executing motor, gearbox and friction models"
    DTDFVocab:enables RealTimeFrictionIdentificationService, DataVisualizationService
]

instance MQTTBroker : DTDFVocab:Enabler [
    base:desc "MQTT broker streaming live sensor data to the digital shadow"
    DTDFVocab:enables DataVisualizationService
]

instance AssetAdministrationShell : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell integrating model data and enabling parameter updates"
    DTDFVocab:enables FrictionParameterUpdateService
]

instance VisualizationDashboard : DTDFVocab:Enabler [
    base:desc "Dashboard visualizing live and simulated data for operators"
    DTDFVocab:enables DataVisualizationService
]

// C6: Services
instance RealTimeFrictionIdentificationService : DTDFVocab:Service [
    base:desc "Real‑time identification of static, kinetic and viscous friction using combined white‑box and black‑box models"
    DTDFVocab:provides FrictionParameterFeedbackInsight, UpdateFrictionParametersAction
]

instance DataVisualizationService : DTDFVocab:Service [
    base:desc "Visualization of live sensor data and simulated model outputs in an operator dashboard"
    DTDFVocab:provides LiveDataVisualizationInsight
]

instance FrictionParameterUpdateService : DTDFVocab:Service [
    base:desc "Generation and injection of updated friction parameters into the robot controller for improved motion accuracy"
    DTDFVocab:provides ModelBasedControlAdjustmentInsight, ApplyFrictionParameterUpdateAction
