// C17: Insights
instance FrictionParameterFeedbackInsight : DTDFVocab:Insight [
    base:desc "Derived friction parameters are fed back to the robot controller to enhance motion accuracy"
]

instance ModelBasedControlAdjustmentInsight : DTDFVocab:Insight [
    base:desc "Digital shadow supports model‑based control adjustments based on updated parameters"
]

instance LiveDataVisualizationInsight : DTDFVocab:Insight [
    base:desc "Operators receive live visual feedback of sensor and simulation data"
]

// C17: Actions
instance UpdateFrictionParametersAction : DTDFVocab:Action [
    base:desc "Automatic update of friction parameters in the controller"
    DTDFVocab:IsAutomatic true
]

instance ApplyFrictionParameterUpdateAction : DTDFVocab:Action [
    base:desc "Apply newly identified friction parameters to the robot motion control loop"
    DTDFVocab:IsAutomatic true
]

